2	import { describe, it, expect } from "vitest";
3	import { execFile } from "node:child_process";
4	
5	type CliResult = {
6	  stdout: string;
7	  stderr: string;
8	  exitCode: number | null;
9	};
10	
11	const runCli = (input: string): Promise<CliResult> =>
12	  new Promise((resolve, reject) => {
13	    const child = execFile(
14	      "npx",
15	      ["tsx", "src/cli.ts"],
16	      (error, stdout, stderr) => {
17	        if (error && error.code === undefined) {
18	          reject(error);
19	          return;
20	        }
21	        resolve({
22	          stdout,
23	          stderr,
24	          exitCode: child.exitCode,
25	        });
26	      }
27	    );
28	    child.stdin?.write(input);
29	    child.stdin?.end();
30	  });
31	
32	describe("Claim Office CLI", () => {
33	  it(
34	    "should write {\"results\": [...]} JSON to stdout and exit with code 0 for a valid scenario (quote silver amulet ench 2 → premium 59; claim fire amulet 200 → payout 100, remainingCap 1100)",
35	    async () => {
36	      const scenario = {
37	        customer: { yearsWithMHPCO: 5 },
38	        steps: [
39	          {
40	            op: "quote",
41	            items: [
42	              {
43	                type: "amulet",
44	                material: "silver",
45	                enchantment: 2,
46	                cursed: false,
47	              },
48	            ],
49	          },
50	          {
51	            op: "claim",
52	            policy: 0,
53	            incident: {
54	              cause: "fire",
55	              damages: [{ itemType: "amulet", amount: 200 }],
56	            },
57	          },
58	        ],
59	      };
60	
61	      const { stdout, exitCode } = await runCli(JSON.stringify(scenario));
62	
63	      expect(JSON.parse(stdout)).toEqual({
64	        results: [{ premium: 59 }, { payout: 100, remainingCap: 1100 }],
65	      });
66	      expect(exitCode).toBe(0);
67	    },
68	    20000
69	  );
70	  it.todo(
71	    "should exit with a non-zero code, write an error description to stderr, and write no results to stdout for an unknown item type"
72	  );
73	});
